+                System.out.print(" : primOnly: " + primOnly[i] + " (" + primOnly[i]*100/numberOfFields[i] + "%)");
+                System.out.print(" valOnly: " + valOnly[i] + " (" + valOnly[i]*100/numberOfFields[i] + "%)");
